changeSet.sql:
CREATE TABLE audit_events (
    id             UUID         NOT NULL DEFAULT gen_random_uuid(),
    tenant_id      UUID,
    actor_id       UUID         NOT NULL,
    actor_email    VARCHAR(255) NOT NULL,
    action         VARCHAR(100) NOT NULL,
    resource_type  VARCHAR(100),
    resource_id    UUID,
    metadata       JSONB,
    ip_address     VARCHAR(45),
    correlation_id VARCHAR(36),
    created_at     TIMESTAMPTZ  NOT NULL DEFAULT NOW(),
    CONSTRAINT pk_audit_events PRIMARY KEY (id)
);

-- Primary access pattern: "show audit log for tenant, newest first"
CREATE INDEX idx_audit_tenant_created
    ON audit_events (tenant_id, created_at DESC);

-- "show all actions by this actor"
CREATE INDEX idx_audit_actor
    ON audit_events (actor_id, created_at DESC);

-- "show audit history for a specific patient / order / etc."
CREATE INDEX idx_audit_resource
    ON audit_events (resource_type, resource_id);

-- Flexible metadata queries (SUPER_ADMIN forensics)
CREATE INDEX idx_audit_metadata
    ON audit_events USING GIN (metadata);

COMMENT ON TABLE  audit_events              IS 'Immutable audit log. Rows are never updated or deleted.';
COMMENT ON COLUMN audit_events.tenant_id    IS 'NULL for SUPER_ADMIN platform actions.';
COMMENT ON COLUMN audit_events.actor_id     IS 'Logical reference to users.id — intentionally no FK to survive user deletion.';
COMMENT ON COLUMN audit_events.action       IS 'Enum-style string: LOGIN, CREATE_PATIENT, UPDATE_ORDER_STATUS, etc.';
COMMENT ON COLUMN audit_events.metadata     IS 'JSONB context. MUST NOT contain patient result values (PHI). Store IDs and status transitions only.';
